import{c as s}from"./app.8935f5f1.js";const a={},e=s('<h2 id="centos-7-0下docker的安装" tabindex="-1"><a class="header-anchor" href="#centos-7-0下docker的安装" aria-hidden="true">#</a> CentOS 7.0下Docker的安装</h2><ol><li>查看内核版本(Docker需要64位版本，同时内核版本在3.10以上，如果版本低于3.10，需要升级内核)：</li></ol><div class="language-bash ext-sh"><pre class="language-bash"><code><span class="token function">uname</span> -r\n</code></pre></div><ol start="2"><li>更新yum包：</li></ol><div class="language-bash ext-sh"><pre class="language-bash"><code>yum update\n</code></pre></div><ol start="3"><li>使用脚本自动安装：</li></ol><div class="language-bash ext-sh"><pre class="language-bash"><code>$ <span class="token function">curl</span> -fsSL get.docker.com -o get-docker.sh\n$ <span class="token function">sudo</span> <span class="token function">sh</span> get-docker.sh --mirror Aliyun\n</code></pre></div><ol start="4"><li>启动Docker</li></ol><div class="language-bash ext-sh"><pre class="language-bash"><code>$ <span class="token function">sudo</span> systemctl <span class="token builtin class-name">enable</span> docker\n$ <span class="token function">sudo</span> systemctl start docker\n</code></pre></div><ol start="5"><li>使用Docker国内镜像（为Docker镜像下载提速，非必须）</li></ol>',10);a.render=function(s,a){return e};export{a as default};
